// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.estimation;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.DataOutputStream;
import java.io.IOException;
import java.io.OutputStream;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class QuadSynopsisPersistenceTest {

	private static final QuadSnapshotIdentity IDENTITY = new QuadSnapshotIdentity(101L, 202L, 9L);

	@TempDir
	Path directory;

	@Test
	void versionEightRoundTripsPrimitiveState() throws IOException {
		QuadSynopsisBudget budget = QuadSynopsisBudget.create(4L * 1024L * 1024L, 16);
		QuadSynopsisBuilder builder = new QuadSynopsisBuilder(budget, IDENTITY, 44L);
		builder.add(1L, 2L, 3L, 4L);
		builder.add(1L, 2L, 5L, 4L);
		QuadSynopsisSnapshot expected = builder.build();
		Path file = directory.resolve("synopsis-v8.bin");

		QuadSynopsisPersistence.write(file, expected);
		QuadSynopsisLoadResult result = QuadSynopsisPersistence.read(file, budget);

		assertFalse(result.rebuildRequired());
		assertEquals(IDENTITY, result.durableIdentity());
		QuadSynopsisSnapshot actual = result.snapshot().orElseThrow();
		assertEquals(44L, actual.snapshotVersion());
		assertEquals(2L, actual.totalRows());
		assertEquals(expected.coldSample(), actual.coldSample());
		assertArrayEquals(expected.table(QuadProbe.SUBJECT).copyCounters(),
				actual.table(QuadProbe.SUBJECT).copyCounters());
	}

	@Test
	void checksumFailurePreservesIdentityAndRequestsRebuild() throws IOException {
		QuadSynopsisBudget budget = QuadSynopsisBudget.create(4L * 1024L * 1024L, 8);
		QuadSynopsisSnapshot snapshot = new QuadSynopsisBuilder(budget, IDENTITY, 3L).build();
		Path file = directory.resolve("corrupt.bin");
		QuadSynopsisPersistence.write(file, snapshot);
		byte[] bytes = Files.readAllBytes(file);
		bytes[bytes.length - Long.BYTES - 1] ^= 0x5a;
		Files.write(file, bytes);

		QuadSynopsisLoadResult result = QuadSynopsisPersistence.read(file, budget);

		assertTrue(result.rebuildRequired());
		assertEquals(IDENTITY, result.durableIdentity());
		assertTrue(result.snapshot().isEmpty());
	}

	@Test
	void versionSevenMigratesOnlyDurableIdentity() throws IOException {
		Path file = directory.resolve("metadata.bin");
		try (OutputStream stream = Files.newOutputStream(file);
				DataOutputStream output = new DataOutputStream(stream)) {
			output.write(new byte[] { 'R', 'J', 'E', 'D' });
			output.writeInt(7);
			output.writeLong(IDENTITY.storeIdHigh());
			output.writeLong(IDENTITY.storeIdLow());
			output.writeLong(IDENTITY.mutationVersion());
		}

		QuadSynopsisLoadResult result = QuadSynopsisPersistence.read(file,
				QuadSynopsisBudget.create(4L * 1024L * 1024L, 0));

		assertTrue(result.rebuildRequired());
		assertEquals(IDENTITY, result.durableIdentity());
		assertTrue(result.snapshot().isEmpty());
	}

	@Test
	void unknownPayloadVersionStillPreservesDurableIdentity() throws IOException {
		Path file = directory.resolve("future.bin");
		try (OutputStream stream = Files.newOutputStream(file);
				DataOutputStream output = new DataOutputStream(stream)) {
			output.writeInt(0x524a5138);
			output.writeInt(99);
			IDENTITY.writeTo(output);
		}

		QuadSynopsisLoadResult result = QuadSynopsisPersistence.read(file,
				QuadSynopsisBudget.create(4L * 1024L * 1024L, 0));

		assertTrue(result.rebuildRequired());
		assertEquals(IDENTITY, result.durableIdentity());
		assertTrue(result.snapshot().isEmpty());
	}
}
